challenge_result.investigation_instruction:
{
  "plans": [
    {
      "hypothesis_id": "h1",
      "hypothesis_statement": "The UPF is the source of media packet loss, dropping traffic between its N3-interface ingress and its media-proxy-facing egress.",
      "primary_suspect_nf": "upf",
      "probes": [
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "window_seconds=60",
          "expected_if_hypothesis_holds": "A significant imbalance between UPF's ingress and egress packet rates, where egress is much lower than ingress.",
          "falsifying_observation": "The UPF's ingress and egress packet rates are balanced, indicating it is not dropping an anomalous number of packets.",
          "conflates_with": []
        },
        {
          "tool": "get_diagnostic_metrics",
          "args_hint": "nf=upf",
          "expected_if_hypothesis_holds": "UPF's internal metrics for dropped GTP packets are significantly elevated.",
          "falsifying_observation": "UPF's internal metrics for dropped GTP packets are zero or nominal.",
          "conflates_with": []
        },
        {
          "tool": "get_diagnostic_metrics",
          "args_hint": "nf=smf",
          "expected_if_hypothesis_holds": "Metrics on the SMF related to N4/PFCP sessions show no errors, indicating the control plane is stable.",
          "falsifying_observation": "The SMF reports errors or failures related to the N4/PFCP interface, suggesting a broader problem at the UPF than just media plane packet loss.",
          "conflates_with": []
        }
      ],
      "notes": "This plan tests the hypothesis that the UPF is internally dropping media packets. It first checks for a packet rate discrepancy across the UPF, then for internal drop counters, and finally checks the health of the control-plane interface to ensure the problem is isolated to the media plane as hypothesized."
    },
    {
      "hypothesis_id": "h2",
      "hypothesis_statement": "RTPEngine is the source of the media plane failure, dropping RTP packets as they arrive from the UPF.",
      "primary_suspect_nf": "rtpengine",
      "probes": [
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "window_seconds=60",
          "expected_if_hypothesis_holds": "The packet loss ratio reported for RTPEngine is high.",
          "falsifying_observation": "The packet loss ratio reported for RTPEngine is zero or nominal, which contradicts the event that generated this hypothesis.",
          "conflates_with": [
            "The UPF could be dropping packets before they reach RTPEngine."
          ]
        },
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "window_seconds=60, specifically observing UPF egress quality",
          "expected_if_hypothesis_holds": "The packet loss ratio reported at the egress of the UPF is zero or nominal, indicating packets are successfully leaving the UPF towards RTPEngine.",
          "falsifying_observation": "The packet loss ratio reported at the egress of the UPF is high. This would prove that packets are already lost before reaching RTPEngine, falsifying the hypothesis.",
          "conflates_with": []
        },
        {
          "tool": "get_diagnostic_metrics",
          "args_hint": "nf=rtpengine",
          "expected_if_hypothesis_holds": "RTPEngine's metrics for discarded packets or processing errors are elevated.",
          "falsifying_observation": "RTPEngine's metrics for discarded packets and processing errors are zero or nominal.",
          "conflates_with": []
        }
      ],
      "notes": "This plan addresses the ambiguity of whether RTPEngine is the source of packet loss or just the reporter. It uses a pair of observations from get_dp_quality_gauges to localize the loss (is it happening before or at RTPEngine?). It also checks RTPEngine's own metrics for direct evidence of malfunction. This structure corrects the issues flagged in the resample feedback."
    }
  ]
}

